+    #[test]
+    fn integers_endpoint_full_i64_range_is_bounded() {
+        let mut rng = oracle_gen();
+        let samples = rng
+            .integers_endpoint(i64::MIN, i64::MAX, 16)
+            .expect("full i64 range should succeed");
